generated_oml:
// C1: Physical Sensing Components
instance MotorEncoder : DTDFVocab:SensingComponent [
    base:desc "Position encoder mounted directly on the robot's motor to measure angular position of the first vertical axis"
]

instance GearboxEncoder : DTDFVocab:SensingComponent [
    base:desc "Position encoder mounted behind the cycloidal gearbox to measure output angle of the first vertical axis"
]

instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Current sensor measuring input motor current (I_M) for torque estimation via known motor constants"
]

// C2: Data Transmission
instance MotorEncoderData : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorEncoder
]

instance GearboxEncoderData : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxEncoder
]

instance MotorCurrentData : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

// C3: Data Types
instance EncoderAngleData : DTDFVocab:Data [
    base:desc "Measured angular position data from both motor and gearbox encoders (input and output angles)"
    DTDFVocab:fromData MotorEncoderData, GearboxEncoderData
]

instance TorqueEstimationData : DTDFVocab:Data [
    base:desc "Torque values derived from motor current using manufacturer-specific constants"
    DTDFVocab:inputTo TorqueEstimationEnabler
]

instance DerivedVelocityData : DTDFVocab:Data [
    base:desc "Angular velocity data calculated from encoder angle measurements"
    DTDFVocab:fromData EncoderAngleData
]

// C4: Physical Acting Components
instance CycloidalGearbox : DTDFVocab:ActingComponent [
    base:desc "Cycloidal gearbox component of the first vertical axis robot assembly, transmitting rotational motion with high torque capacity"
]

instance MotorDriveUnit : DTDFVocab:ActingComponent [
    base:desc "Electrical motor drive unit providing rotational power to the robot's first vertical axis"
]

// C5: Models/Data - Engineering Models
instance RobotAxisStructure : DTDFVocab:Model [
    base:desc "SysML Block Definition Diagram describing the first vertical axis as composition of Motor → Gearwheel → Cycloidal Gearbox with rotational (torque/velocity) and electrical (current) energy flows"
    DTDFVocab:inputTo SysMLToolingEnabler
]

instance FrictionModels : DTDFVocab:Model [
    base:desc "Executable MathWorks MATLAB Simulink models implementing Coulomb-Viscous, Stribeck, and LuGre friction models for simulating friction effects"
    DTDFVocab:inputTo MATLABSimulinkEnabler
]

instance TorqueEstimationModel : DTDFVocab:Model [
    base:desc "Model deriving torque from motor current using manufacturer-specific constants and gearbox ratios"
    DTDFVocab:inputTo TorqueEstimationEnabler
]

// C6: Enablers/Tools
instance SysMLToolingEnabler : DTDFVocab:Enabler [
    base:desc "SysML modeling tool used for creating structural and behavioral SysML Block Definition Diagrams (BDDs) and Internal Block Diagrams (IBDs) of the robot's first axis"
]

instance MATLABSimulinkEnabler : DTDFVocab:Enabler [
    base:desc "MathWorks MATLAB Simulink environment for developing and executing friction models (Coulomb-Viscous, Stribeck, LuGre) and simulations"
]

instance TorqueEstimationEnabler : DTDFVocab:Enabler [
    base:desc "Data processing enabler deriving torque values from motor current measurements using manufacturer-specific constants and gearbox parameters"
]

instance MQTTSensorStreaming : DTDFVocab:Enabler [
    base:desc "MQTT protocol implementation for real-time sensor data streaming from robot encoders and motor current to digital twin"
]

instance CustomDashboard : DTDFVocab:Enabler [
    base:desc "Custom visualization dashboard displaying real-time data traces (measured vs. simulated) and enabling interactive analysis"
]

// C7: Services
instance FrictionAnalysisService : DTDFVocab:Service [
    base:desc "Continuous identification and refinement of white-box (analytical) and black-box (data-driven) friction models (Coulomb-Viscous, Stribeck, LuGre) using live sensor data"
    DTDFVocab:provides FrictionModelInsight
]

instance ModelOptimizationService : DTDFVocab:Service [
    base:desc "Dynamic updating of friction models to minimize motion inaccuracies (up to 30% due to friction) during real-time operation"
    DTDFVocab:provides ModelUpdateAction
]

instance VisualizationService : DTDFVocab:Service [
    base:desc "Unified dashboard displaying real-time data traces (measured vs. simulated torque/velocity) with interactive analysis capabilities"
    DTDFVocab:provides VisualAnalyticsInsight
]

instance ControlOptimizationService : DTDFVocab:Service [
    base:desc "Provides insights into friction-induced deviations to enable adjustments to control algorithms for enhanced robot motion accuracy"
    DTDFVocab:provides ControlAdjustmentAction
]

instance DataStreamingService : DTDFVocab:Service [
    base:desc "Real-time aggregation and processing of sensor data streams (MQTT protocol) from robot encoders and motor current"
    DTDFVocab:provides DataTraceInsight
]

// C8: Insights/Actions
instance FrictionModelInsight : DTDFVocab:Insight [
    base:desc "Real-time detection of static, kinetic, and viscous friction components enabling adjustments to control algorithms"
]

instance ModelUpdateAction : DTDFVocab:Action [
    base:desc "Automatically updates friction models during operation to adapt to changes in friction (wear, load variations)"
    DTDFVocab:IsAutomatic true
]

instance VisualAnalyticsInsight : DTDFVocab:Insight [
    base:desc "Dashboard visualizations highlighting deviations between measured and simulated data to guide corrective actions"
]

instance ControlAdjustmentAction : DTDFVocab:Action [
    base:desc "Manual or automated adjustment of control algorithms based on friction model insights to improve motion accuracy"
    DTDFVocab:IsAutomatic false
]

instance DataTraceInsight : DTDFVocab:Insight [
    base:desc "Semantic understanding of data traces with timestamped measurements from multiple sensors for traceability"
]

// C9: Environment
instance RobotFirstAxisEnvironment : DTDFVocab:Environment [
    base:contains MotorDriveUnit, CycloidalGearbox,
                 MotorEncoder, GearboxEncoder, MotorCurrentSensor,
                 RobotAxisStructure, FrictionModels, TorqueEstimationModel
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "The twinning time scale is **real-time and event-driven**:
  - **Data acquisition frequency**: Sensor data (e.g., motor current, encoder readings) is streamed at **high temporal resolution** (not explicitly quantified but assumed to be sub-second intervals for dynamic friction modeling).
  - **Model update frequency**: Friction models are dynamically updated during operation to reflect changes in wear, load, or environmental conditions.
  - **Dashboard synchronization**: Visualization updates in real-time to reflect live data and model predictions."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "The digital twin constellation is **single-axis focused**:
  - **Centralized architecture**: The digital shadow is a **standalone entity** linked to the physical robot’s first axis, with no mention of decentralized or multi-axis integration.
  - **Asset Administration Shell (AAS) integration**: The DT leverages AAS principles to structure the robot’s data and models, ensuring traceability and semantic support for friction analysis."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "The digital twin operates across the **operational lifecycle stage** of the physical system:
  - **Representation phase**: Focuses on the **as-operated** state, emphasizing real-time friction analysis and control optimization during machining tasks.
  - **No explicit stages for design or manufacturing** are described; the DT is primarily used for **continuous improvement of motion accuracy during runtime**."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Fidelity and validity considerations include:
  - **Data traceability**: Each data point is linked to its source (e.g., encoder, motor current) and computational method, ensuring transparency in model predictions.
  - **Model validation**: Friction models (white-box/black-box) are validated against live measurements to detect deviations (e.g., friction-induced inaccuracies).
  - **Uncertainty handling**: The DT accounts for physical uncertainties (e.g., gearbox elasticity, encoder resolution) by comparing simulated vs. measured data to identify friction losses.
  - **Verification/validation**: Implicitly validated through real-time comparison of simulated and measured torque/velocity traces in the dashboard."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "The DT technical connection uses:
  - **MQTT protocol** for real-time data streaming from the robot’s sensors (encoders, motor current).
  - **Asset Administration Shell (AAS)**: Structures the DT’s data and models to ensure semantic alignment with the physical system.
  - **SysML models**: Enables integration of structural and behavioral components (e.g., motor, gearbox) in the DT."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "The DT incorporates:
  - **SysML** for structural modeling (compliant with SysML 1.7 standards).
  - **Asset Administration Shell (AAS)**: Aligns with Industry 4.0 standards for digital twin integration.
  - **MQTT protocol**: Standardized for IoT/IIoT data communication."
]
